import{_ as d,C as a,o as l,c as o,a0 as e,E as n}from"./chunks/framework.OSBK0N2m.js";const m=JSON.parse('{"title":"Завантаження 3D-моделей з Blender","description":"Як експортувати модель з Blender та переглянути її у браузері з інтерактивним керуванням камерою","frontmatter":{"layout":"page","title":"Завантаження 3D-моделей з Blender","description":"Як експортувати модель з Blender та переглянути її у браузері з інтерактивним керуванням камерою"},"headers":[],"relativePath":"blender-model.md","filePath":"blender-model.md"}'),s={name:"blender-model.md"};function i(h,t,c,g,p,b){const r=a("BlenderModel",!0);return l(),o("div",null,[t[0]||(t[0]=e('<h1 id="завантаження-3d-моделеи-з-blender" tabindex="-1">Завантаження 3D-моделей з Blender <a class="header-anchor" href="#завантаження-3d-моделеи-з-blender" aria-label="Permalink to &quot;Завантаження 3D-моделей з Blender&quot;">​</a></h1><h2 id="вступ" tabindex="-1">Вступ <a class="header-anchor" href="#вступ" aria-label="Permalink to &quot;Вступ&quot;">​</a></h2><p>У цьому розділі ви навчитесь завантажувати 3D-моделі, створені в <strong>Blender</strong>, прямо у вебсторінку та взаємодіяти з ними: обертати камеру, масштабувати та переміщувати.</p><p>Для відображення моделей у браузері ми використовуємо формат <strong>glTF / GLB</strong> — відкритий стандарт передачі 3D-сцен, який підтримується Three.js та більшістю 3D-рушіїв.</p><hr><h2 id="інтерактивнии-переглядач" tabindex="-1">Інтерактивний переглядач <a class="header-anchor" href="#інтерактивнии-переглядач" aria-label="Permalink to &quot;Інтерактивний переглядач&quot;">​</a></h2><p>Завантажте свою модель у форматі <code>.glb</code> або <code>.gltf</code>, натиснувши кнопку нижче, або перетягніть файл у зону завантаження:</p>',7)),n(r,{height:"600px","auto-rotate":""}),t[1]||(t[1]=e(`<hr><h2 id="інструкція-з-експорту-моделі-з-blender" tabindex="-1">Інструкція з експорту моделі з Blender <a class="header-anchor" href="#інструкція-з-експорту-моделі-з-blender" aria-label="Permalink to &quot;Інструкція з експорту моделі з Blender&quot;">​</a></h2><h3 id="крок-1-—-підготовка-сцени" tabindex="-1">Крок 1 — Підготовка сцени <a class="header-anchor" href="#крок-1-—-підготовка-сцени" aria-label="Permalink to &quot;Крок 1 — Підготовка сцени&quot;">​</a></h3><ol><li>Відкрийте вашу модель у <strong>Blender</strong>.</li><li>Переконайтесь, що всі об&#39;єкти мають <strong>застосовані трансформації</strong>: <ul><li>Виділіть усі об&#39;єкти (<code>A</code>)</li><li>Натисніть <code>Ctrl + A</code> → <strong>All Transforms</strong></li></ul></li><li>Перевірте, що матеріали використовують <strong>Principled BSDF</strong> шейдер — він найкраще конвертується у glTF.</li></ol><h3 id="крок-2-—-налаштування-матеріалів" tabindex="-1">Крок 2 — Налаштування матеріалів <a class="header-anchor" href="#крок-2-—-налаштування-матеріалів" aria-label="Permalink to &quot;Крок 2 — Налаштування матеріалів&quot;">​</a></h3><p>Формат glTF підтримує такі карти з Principled BSDF:</p><table tabindex="0"><thead><tr><th>Параметр Blender</th><th>Що експортується</th></tr></thead><tbody><tr><td>Base Color</td><td>Колір / текстура альбедо</td></tr><tr><td>Metallic</td><td>Карта металічності</td></tr><tr><td>Roughness</td><td>Карта шорсткості</td></tr><tr><td>Normal Map</td><td>Карта нормалей</td></tr><tr><td>Emission</td><td>Емісійне світло</td></tr><tr><td>Alpha</td><td>Прозорість</td></tr></tbody></table><blockquote><p>💡 <strong>Порада:</strong> Уникайте складних нодових дерев — використовуйте тільки ті ноди, що безпосередньо підключені до Principled BSDF.</p></blockquote><h3 id="крок-3-—-експорт-у-gltf-glb" tabindex="-1">Крок 3 — Експорт у glTF / GLB <a class="header-anchor" href="#крок-3-—-експорт-у-gltf-glb" aria-label="Permalink to &quot;Крок 3 — Експорт у glTF / GLB&quot;">​</a></h3><ol><li>Перейдіть у меню <strong>File → Export → glTF 2.0 (.glb / .gltf)</strong></li><li>У панелі налаштувань експорту задайте:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Формат:              glTF Binary (.glb)    ← рекомендовано</span></span>
<span class="line"><span>Текстури:            Include (вбудовані)</span></span>
<span class="line"><span>Анімації:            ✅ (якщо потрібно)</span></span>
<span class="line"><span>Apply Modifiers:     ✅</span></span>
<span class="line"><span>UV:                  ✅</span></span>
<span class="line"><span>Normals:             ✅</span></span>
<span class="line"><span>Vertex Colors:       якщо використовуєте</span></span></code></pre></div><ol start="3"><li>Натисніть <strong>Export glTF 2.0</strong>.</li></ol><h3 id="рекомендовані-параметри" tabindex="-1">Рекомендовані параметри <a class="header-anchor" href="#рекомендовані-параметри" aria-label="Permalink to &quot;Рекомендовані параметри&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Параметр</th><th>Значення</th><th>Пояснення</th></tr></thead><tbody><tr><td><strong>Format</strong></td><td>glTF Binary (.glb)</td><td>Один файл, легше завантажувати</td></tr><tr><td><strong>Include</strong></td><td>Selected Objects</td><td>Експортувати лише вибрані об&#39;єкти</td></tr><tr><td><strong>Transform → +Y Up</strong></td><td>✅</td><td>Three.js використовує Y-вгору</td></tr><tr><td><strong>Geometry → Apply Modifiers</strong></td><td>✅</td><td>Застосувати модифікатори перед експортом</td></tr><tr><td><strong>Geometry → UVs</strong></td><td>✅</td><td>Необхідно для текстур</td></tr><tr><td><strong>Geometry → Normals</strong></td><td>✅</td><td>Для коректного освітлення</td></tr><tr><td><strong>Animation</strong></td><td>за потреби</td><td>Увімкніть якщо модель має анімацію</td></tr><tr><td><strong>Compression</strong></td><td>Draco (опція)</td><td>Зменшує розмір файлу, потребує додатковий декодер</td></tr></tbody></table><hr><p><strong>Управління мишкою:</strong></p><table tabindex="0"><thead><tr><th>Дія</th><th>Ефект</th></tr></thead><tbody><tr><td>Ліва кнопка + рух</td><td>Обертання навколо моделі</td></tr><tr><td>Права кнопка + рух</td><td>Переміщення (панорама)</td></tr><tr><td>Колесо прокрутки</td><td>Наближення / віддалення</td></tr><tr><td>Середня кнопка + рух</td><td>Переміщення (панорама)</td></tr></tbody></table><hr><h2 id="поширені-проблеми" tabindex="-1">Поширені проблеми <a class="header-anchor" href="#поширені-проблеми" aria-label="Permalink to &quot;Поширені проблеми&quot;">​</a></h2><h3 id="модель-не-відображається" tabindex="-1">Модель не відображається <a class="header-anchor" href="#модель-не-відображається" aria-label="Permalink to &quot;Модель не відображається&quot;">​</a></h3><ul><li>Переконайтесь, що файл має розширення <code>.glb</code> або <code>.gltf</code></li><li>Перевірте, чи застосовані всі модифікатори в Blender перед експортом</li><li>Перевірте консоль браузера (F12) на помилки</li></ul><h3 id="модель-занадто-темна" tabindex="-1">Модель занадто темна <a class="header-anchor" href="#модель-занадто-темна" aria-label="Permalink to &quot;Модель занадто темна&quot;">​</a></h3><ul><li>Переконайтесь, що матеріали використовують <strong>Principled BSDF</strong></li><li>Перевірте, чи текстури вбудовані у файл (опція «Include» при експорті)</li></ul><h3 id="текстури-відсутні" tabindex="-1">Текстури відсутні <a class="header-anchor" href="#текстури-відсутні" aria-label="Permalink to &quot;Текстури відсутні&quot;">​</a></h3><ul><li>При експорті у <code>.glb</code> текстури мають бути <strong>вбудованими</strong> (embedded)</li><li>При експорті у <code>.gltf</code> переконайтесь, що папка з текстурами поруч із файлом</li></ul><h3 id="модель-перевернута-або-має-неправильнии-масштаб" tabindex="-1">Модель перевернута або має неправильний масштаб <a class="header-anchor" href="#модель-перевернута-або-має-неправильнии-масштаб" aria-label="Permalink to &quot;Модель перевернута або має неправильний масштаб&quot;">​</a></h3><ul><li>У Blender застосуйте <code>Ctrl + A</code> → <strong>All Transforms</strong> перед експортом</li><li>Встановіть <strong>+Y Up</strong> у налаштуваннях експорту glTF</li></ul><hr><h2 id="підсумок" tabindex="-1">Підсумок <a class="header-anchor" href="#підсумок" aria-label="Permalink to &quot;Підсумок&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Що ми навчились</th><th>Інструмент / концепція</th></tr></thead><tbody><tr><td>Завантаження 3D-моделей у браузер</td><td><code>GLTFLoader</code> (Three.js)</td></tr><tr><td>Інтерактивне керування камерою</td><td><code>OrbitControls</code> (Three.js)</td></tr><tr><td>Експорт моделей з Blender</td><td>glTF 2.0 (.glb)</td></tr><tr><td>Студійне освітлення для 3D-сцени</td><td>Ambient + Directional + Hemisphere</td></tr><tr><td>Автоматичне кадрування</td><td>Bounding Box → Camera Fit</td></tr></tbody></table>`,30))])}const f=d(s,[["render",i]]);export{m as __pageData,f as default};
